var e=[{id:`L2_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_NULL`,text:{KOREA:`궂은 눈보라를 뚫고 나타난 게 고작 특종거리를 찾아온 방송국 헬기라.`,JPN:`吹雪を突破して現れたのが、単なるスクープ狙いの放送局のヘリとは。`,ENG:`After braving the thick snowstorm, all that appeared was a media helicopter here for a scoop…`,TWN:`穿越暴風雪抵達的竟然是來找獨家新聞的電視台直升機。`},stage:{bg:`COUNTERSIDE_GRAVE`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_NULL`,text:{KOREA:`세상의 종말을 앞두고도 샤레이드는 참 한결 같군요.`,JPN:`世界の終末が目前に迫っているのに、シャレードは変わりませんね。`,ENG:`Even with the end of the world at hand, Charade has not changed.`,TWN:`即使面臨著世界末日，查雷德也還是老樣子。`},stage:{bg:`COUNTERSIDE_GRAVE`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MITCH_NPC_NULL_NULL`,text:{KOREA:`방금 저기서 뭔가 반짝인 것 같은데? 카메라 확대해줘요!`,JPN:`今あそこで何か光ったようですよ？　カメラさん拡大してください！`,ENG:`Didn't something just flash over there? Zoom in with the camera!`,TWN:`那裡好像有個東西在發光？鏡頭拉近！`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`MITCH_NPC_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CAMERA_NPC_NULL_NULL`,text:{KOREA:`저기 있는 사람… 스완이잖아?`,JPN:`あそこにいる人って……スワンじゃない？`,ENG:`Isn't that... Swan?!`,TWN:`那邊那個人……是史旺吧？`},stage:{bg:`COUNTERSIDE_GRAVE`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MITCH_NPC_NULL_NULL`,text:{KOREA:`네? 관리국에서 수배 중인 스완이 왜 여기에 있는 거죠?`,JPN:`はい？　管理局から手配中のスワンが何故ここにいるんですか？`,ENG:`Huh? Why's Swan, one of the Administration's most wanted, over there?`,TWN:`什麼？被管理局通緝的史旺為什麼會在這裡？`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`MITCH_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`전방으로부터 에너지 발사체 감지! 이쪽으로 옵니다!`,JPN:`前方からエネルギー発射体を感知！　こっちに来ます！`,ENG:`Detecting an energy projectile in front! It's headed toward us!`,TWN:`前方探測到能量發射物！朝這邊飛來了！`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`MITCH_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MITCH_NPC_NULL_NULL`,text:{KOREA:`뭐라고요? 잠깐…!`,JPN:`なんですって？　ちょっと……！`,ENG:`Say what? Hold on a sec...!`,TWN:`什麼？等等……！`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`MITCH_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`발사체가… 갑자기 비껴갔어?`,JPN:`発射体が……いきなり反れた？`,ENG:`The projectile... missed us?`,TWN:`發射物……射偏了？`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`공격은 제가 막을게요. 이대로 계속 접근해 주세요.`,JPN:`攻撃は私が防ぎます。このまま接近してください。`,ENG:`I'll block the attacks. Just keep going.`,TWN:`我來阻擋攻擊，繼續前進吧。`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`현장의 전투를 확실하게 포착해야 하니까요.`,JPN:`現場の戦闘状況をしっかりとカメラで捉えなければいけません。`,ENG:`We need to capture the battle going down there with crystal-clear images.`,TWN:`必須完整捕捉到現場的戰鬥畫面。`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`MITCH_NPC_NULL_NULL`,text:{KOREA:`방금 스완이 우릴 노린 거죠?! 맞죠?!`,JPN:`今スワンが私たちを狙ったんですよね！？　ですよね！？`,ENG:`Swan just tried to kill us, right?!`,TWN:`剛剛是史旺朝我們攻擊的吧？！對不對？！`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`MITCH_NPC_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`이걸로 확실히 알았겠지? 스완은 더이상 당신들이 알던 무해한 유명인사가 아니야.`,JPN:`これでわかっただろう？　スワンはあんたたちが知っていた無害な有名人ではない。`,ENG:`Now do you understand? Swan's no longer the harmless celebrity you thought she was.`,TWN:`這下明白了吧？現在的史旺可不是你們認識的那個單純的知名演員。`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`우리의 적이라고!`,JPN:`私たちの敵だ！`,ENG:`She's our enemy!`,TWN:`而是我們的敵人！`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_NULL`,text:{KOREA:`방금 공격을 왜곡시킨 건… 망원렌즈인가요?`,JPN:`今の攻撃を歪曲させたのは……望遠レンズですか？`,ENG:`My attack was distorted... Was it the Zoom Lens?`,TWN:`剛剛扭曲攻擊軌道的……是望遠鏡？`},stage:{bg:`COUNTERSIDE_GRAVE`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_NULL`,text:{KOREA:`이런 자리에 건틀렛의 챔피언을 데려오다니. 뜻밖의 수긴 하군요.`,JPN:`こんなところにガントレットのチャンピオンを連れてくるとは。予想外の手段ではありますね。`,ENG:`You brought the Gauntlet champion here. That was rather unexpected.`,TWN:`竟然帶來了聖鎧的冠軍。沒想到。`},stage:{bg:`COUNTERSIDE_GRAVE`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};